import * as class_variance_authority_types from 'class-variance-authority/types';
import * as react_jsx_runtime from 'react/jsx-runtime';
import * as React from 'react';
import { Button } from './button.js';
import { VariantProps } from 'class-variance-authority';
import '../../lib/types.js';

/**
 * A container that groups an input with addons, buttons, and other elements into a unified form control.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputGroup>
 *   <InputGroupAddon align="inline-start">
 *     <InputGroupText>https://</InputGroupText>
 *   </InputGroupAddon>
 *   <InputGroupInput placeholder="example.com" />
 *   <InputGroupAddon align="inline-end">
 *     <InputGroupButton>Go</InputGroupButton>
 *   </InputGroupAddon>
 * </InputGroup>
 * ```
 */
declare function InputGroup({ className, onClick, ...props }: React.ComponentProps<'fieldset'>): react_jsx_runtime.JSX.Element;
declare const inputGroupAddonVariants: (props?: ({
    align?: "inline-end" | "inline-start" | "block-end" | "block-start" | null | undefined;
} & class_variance_authority_types.ClassProp) | undefined) => string;
/**
 * A container for non-input elements (icons, text, buttons) placed alongside the input within an `InputGroup`.
 *
 * ### Component Props
 *
 * | Prop     | Type                                                           | Default          |
 * | :------- | :------------------------------------------------------------- | :--------------- |
 * | _align_  | `"inline-start" \| "inline-end" \| "block-start" \| "block-end"` | `"inline-start"` |
 *
 *
 * ### Example Usage
 *
 * **Inline Start**
 * ```tsx
 * <InputGroupAddon align="inline-start">
 *   <SearchIcon />
 * </InputGroupAddon>
 * ```
 *
 * **Inline End**
 * ```tsx
 * <InputGroupAddon align="inline-end">
 *   <InputGroupButton>Go</InputGroupButton>
 * </InputGroupAddon>
 * ```
 *
 * **Block Start**
 * ```tsx
 * <InputGroupAddon align="block-start">
 *   <InputGroupText>Label above input</InputGroupText>
 * </InputGroupAddon>
 * ```
 */
declare function InputGroupAddon({ className, align, ...props }: React.ComponentProps<'div'> & VariantProps<typeof inputGroupAddonVariants>): react_jsx_runtime.JSX.Element;
declare const inputGroupButtonVariants: (props?: ({
    size?: "xs" | "sm" | "icon-xs" | "icon-sm" | null | undefined;
} & class_variance_authority_types.ClassProp) | undefined) => string;
/**
 * A small button designed to be placed inside an `InputGroupAddon`.
 *
 * ### Component Props
 *
 * | Prop       | Type                                      | Default   |
 * | :--------- | :---------------------------------------- | :-------- |
 * | _variant_  | `"ghost" \| "outline" \| ...`             | `"ghost"` |
 * | _size_     | `"xs" \| "sm" \| "icon-xs" \| "icon-sm"` | `"xs"`    |
 *
 *
 * ### Example Usage
 *
 * **Default**
 * ```tsx
 * <InputGroupButton>Submit</InputGroupButton>
 * ```
 *
 * **Icon Extra Small**
 * ```tsx
 * <InputGroupButton size="icon-xs">
 *   <CopyIcon />
 * </InputGroupButton>
 * ```
 *
 * **Outline + Small**
 * ```tsx
 * <InputGroupButton variant="outline" size="sm">
 *   Apply
 * </InputGroupButton>
 * ```
 */
declare function InputGroupButton({ className, type, variant, size, ...props }: Omit<React.ComponentProps<typeof Button>, 'size'> & VariantProps<typeof inputGroupButtonVariants>): react_jsx_runtime.JSX.Element;
/**
 * A text or icon element displayed inside an `InputGroupAddon`.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputGroupText>$</InputGroupText>
 * ```
 */
declare function InputGroupText({ className, ...props }: React.ComponentProps<'span'>): react_jsx_runtime.JSX.Element;
/**
 * An input element styled to integrate seamlessly within an `InputGroup`.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputGroupInput placeholder="Enter a value" />
 * ```
 */
declare function InputGroupInput({ className, size: _size, ...props }: React.ComponentProps<'input'>): react_jsx_runtime.JSX.Element;
/**
 * A textarea element styled to integrate seamlessly within an `InputGroup`.
 *
 * ### Example Usage
 *
 * ```tsx
 * <InputGroupTextarea placeholder="Enter a longer message" />
 * ```
 */
declare function InputGroupTextarea({ className, ...props }: React.ComponentProps<'textarea'>): react_jsx_runtime.JSX.Element;

export { InputGroup, InputGroupAddon, InputGroupButton, InputGroupInput, InputGroupText, InputGroupTextarea };
